mapper.select:
SELECT id, user_id, report_key, name, filter_json, is_default, is_subscribed, sort_order, created_at, updated_at
FROM analytics_user_view
WHERE user_id = #{userId}
  AND report_key = #{reportKey}
ORDER BY is_subscribed DESC, is_default DESC, sort_order ASC, updated_at DESC

mapper.update:
UPDATE analytics_user_view
SET is_default = 0
WHERE user_id = #{userId} AND report_key = #{reportKey}

UPDATE analytics_user_view
SET is_default = 1
WHERE id = #{id} AND user_id = #{userId}

UPDATE analytics_user_view
SET is_subscribed = #{subscribed}
WHERE id = #{id} AND user_id = #{userId}
